import sys

def gcd(a, b):
    if b == 0:
        return a
    else:
        return gcd(b, a % b)

def solve(n, points):
    count = 0
    for i in range(n):
        for j in range(i + 1, n):
            for k in range(j + 1, n):
                for l in range(k + 1, n):
                    if points[i] != points[j] and points[i] != points[k] and points[i] != points[l] and points[j] != points[k] and points[j] != points[l] and points[k] != points[l]:
                        x1 = points[j][0] - points[i][0]
                        y1 = points[j][1] - points[i][1]
                        x2 = points[k][0] - points[i][0]
                        y2 = points[k][1] - points[i][1]
                        x3 = points[l][0] - points[i][0]
                        y3 = points[l][1] - points[i][1]
                        if x1 * y2 == x2 * y1 and x2 * y3 == x3 * y2 and x3 * y1 == x1 * y3:
                            count += 1
    return count

def main():
    n = int(sys.stdin.readline().strip())
    points = []
    for i in range(n):
        x, y = map(int, sys.stdin.readline().strip().split())
        points.append((x, y))
    print(solve(n, points))

if __name__ == "__main__":
    main()
